import{E as e}from"./EditorialStub-B-KerYRH.js";import{b as a,v as t}from"./index-zOR8L73q.js";import"./useReveal-BylAWuYB.js";const l={__name:"Source",setup(o){return(r,i)=>(a(),t(e,{eyebrow:"(Index 00) Source","title-a":"Source","title-b":"Code.",lede:"iMRV is built on open-source foundations. Where our application code is not yet published, we publish the data, the schema, and the methodology so that every figure can be reproduced.","contact-subject":"iMRV Source Code Inquiry","body-paragraphs":["The iMRV platform is built on the Frappe Framework — an MIT-licensed Python and JavaScript stack — combined with a Vue 3 single-page application served at /frontend. The desk-side application logic, doctypes, and data layer are written as a Frappe app called mrvtools; the navigation drawer is a sister app called frappe_side_menu. Both apps follow standard Frappe conventions for installs, migrations, and tests.","Public release of the application source is being staged: the third-party Frappe and Vue components are already open under MIT and BSD licences, and the bespoke MECDM code follows the same direction. We want to publish under a permissive licence with clear attribution back to the Solomon Islands government, but the code review and documentation polish to make that responsibly useful is still in progress.","In the interim, the data layer is the most useful artefact for anyone building on top of our work: it is documented, stable, and accessible via the Open Data API. The methodology page explains how each figure on the public site is computed.","If you are working on a research or partner project that needs source-level access ahead of full publication, write to the address below — we are happy to share under a non-disclosure agreement."]}))}};export{l as default};
